      <el-alert v-if="slittingLockSummary.unlockedRows > 0" type="warning" show-icon :closable="false" class="mb-10" :title="`锁料提醒：当前有 ${slittingLockSummary.unlockedRows} 条待分切订单存在未锁定面积，共 ${slittingLockSummary.unlockedArea} ㎡。建议先处理锁料风险。`" />
      <div class="table-main-area">
        <el-table ref="slittingTable" v-loading="slittingLoading" :data="slittingList" class="manual-schedule-table process-schedule-table" size="mini" border stripe style="width:100%" :max-height="tableHeight" :row-class-name="slittingRowClassName" @selection-change="handleSlittingPrintSelectionChange" @sort-change="handleSlittingSortChange">
