          <el-table-column label="交货日期" width="80" align="center" sortable="custom" column-key="delivery_date"><template slot-scope="scope"><span class="date-text">{{ scope.row.delivery_date | formatDate }}</span></template></el-table-column>
          <el-table-column prop="material_code" label="料号" width="230" class-name="wrap-col" show-overflow-tooltip sortable="custom" column-key="material_code">
            <template slot-scope="scope">
              <el-autocomplete v-if="scope.row.__editing && scope.row.__manual" v-model="scope.row.material_code" size="small" :fetch-suggestions="queryTapeSpecByMaterialCode" placeholder="请输入料号" :trigger-on-focus="false" @input="handleManualSlittingMaterialInput(scope.row, $event)" @select="handleManualSlittingMaterialSelect(scope.row, $event)">
                <template slot-scope="{ item }"><div style="display:flex;flex-direction:column;gap:2px;line-height:1.35;"><span style="font-weight:600;color:#303133;">{{ item.materialCode }}</span><span style="color:#909399;">{{ item.productName || '-' }}</span></div></template>
              </el-autocomplete>
              <span v-else>{{ scope.row.material_code || '-' }}</span>
