          <el-table-column label="产品规格" width="132" align="right" sortable="custom" column-key="spec"><template slot-scope="scope">{{ formatOrderSpec(scope.row) }}</template></el-table-column>
          <el-table-column label="分切卷数" width="84" align="right" sortable="custom" column-key="schedule_qty"><template slot-scope="scope">{{ Number(scope.row.schedule_qty || 0) }}</template></el-table-column>
          <el-table-column label="已报工卷数" width="96" align="right" sortable="custom" column-key="slitting_report_qty"><template slot-scope="scope">{{ Number(scope.row.slitting_report_qty || 0).toFixed(2) }}</template></el-table-column>
          <el-table-column label="已报工面积(㎡)" width="120" align="right"><template slot-scope="scope">{{ formatArea(calcReportedAreaBySpec(scope.row, scope.row.slitting_report_qty)) }}</template></el-table-column>
          <el-table-column label="完成率" width="84" align="center" sortable="custom" column-key="slitting_completion_rate"><template slot-scope="scope">{{ formatProcessCompletionRate(scope.row.slitting_report_qty, scope.row.schedule_qty) }}</template></el-table-column>
          <el-table-column label="分切速度(卷/分)" width="118" align="center" sortable="custom" column-key="slitting_speed">
            <template slot-scope="scope"><el-input-number v-if="scope.row.__editing" v-model="scope.row.manual_slitting_speed" :min="0" :step="1" size="mini" controls-position="right" placeholder="可手输" @change="handleSlittingDateChange(scope.row)" /><span v-else>{{ formatSlittingSpeed(scope.row) }}</span></template>
          </el-table-column>
