            <template slot-scope="scope"><el-date-picker v-if="scope.row.__editing" v-model="scope.row.packaging_date" type="date" size="small" format="yyyy-MM-dd" value-format="yyyy-MM-dd" @change="handleSlittingDateChange(scope.row)" /><span v-else>{{ formatDateOnly(scope.row.packaging_date) }}</span></template>
          </el-table-column>
